#include "rwlock.h"

//---------------------------------------------------------------
// Una solicitud de ingreso.  Cada hilo que debe esperar crea una
// estructura de este tipo y la deposita en una cola fifo.
// La condicion es exclusiva del hilo que hizo la solicitud, de
// modo que solo se despierta al hilo especifico cuya solicitud
// fue aceptada.  Se cumple asi el patron "request".
//---------------------------------------------------------------
struct request {
    pthread_cond_t  cond;     // condicion para despertar al dueno
    int             granted;  // 1 cuando la solicitud fue aceptada
};

//---------------------------------------------------------------
// Estado del controlador lectores/escritores.
//---------------------------------------------------------------
struct rwlock {
    pthread_mutex_t mutex;        // protege todos los campos
    Queue          *waiting_readers;  // fifo de lectores pendientes
    Queue          *waiting_writers;  // fifo de escritores pendientes
    int             n_readers;    // lectores actualmente dentro
    int             writer;       // 1 si hay un escritor dentro
};

RWLock *makeRWLock(void) {
    RWLock *rwl = malloc(sizeof(RWLock));
    pthread_mutex_init(&rwl->mutex, NULL);
    rwl->waiting_readers = makeQueue();
    rwl->waiting_writers = makeQueue();
    rwl->n_readers = 0;
    rwl->writer    = 0;
    return rwl;
}

void destroyRWLock(RWLock *rwl) {
    // No deberia haber solicitudes pendientes al destruir.
    // Aun asi, liberamos eventuales estructuras colgadas.
    while (!emptyQueue(rwl->waiting_readers)) {
        struct request *r = get(rwl->waiting_readers);
        pthread_cond_destroy(&r->cond);
        free(r);
    }
    while (!emptyQueue(rwl->waiting_writers)) {
        struct request *r = get(rwl->waiting_writers);
        pthread_cond_destroy(&r->cond);
        free(r);
    }
    destroyQueue(rwl->waiting_readers);
    destroyQueue(rwl->waiting_writers);
    pthread_mutex_destroy(&rwl->mutex);
    free(rwl);
}

//---------------------------------------------------------------
// Politica de ingreso de un lector:
//   * Se acepta inmediatamente si no hay un escritor trabajando
//     y no hay solicitudes de escritores pendientes.
//   * En caso contrario la solicitud queda pendiente.
//---------------------------------------------------------------
void enterRead(RWLock *rwl) {
    pthread_mutex_lock(&rwl->mutex);

    // Caso favorable: entrar de inmediato.
    if (!rwl->writer && emptyQueue(rwl->waiting_writers)) {
        rwl->n_readers++;
        pthread_mutex_unlock(&rwl->mutex);
        return;
    }

    // Caso pendiente: crear la solicitud, encolarla y esperar.
    struct request *req = malloc(sizeof(struct request));
    pthread_cond_init(&req->cond, NULL);
    req->granted = 0;
    put(rwl->waiting_readers, req);

    // El bucle protege contra despertar espurio.
    while (!req->granted) {
        pthread_cond_wait(&req->cond, &rwl->mutex);
    }

    pthread_cond_destroy(&req->cond);
    free(req);
    pthread_mutex_unlock(&rwl->mutex);
}

//---------------------------------------------------------------
// Salida de un lector:
//   * Si era el ultimo lector y hay escritores pendientes, se
//     acepta al escritor que lleva mas tiempo esperando.
//---------------------------------------------------------------
void exitRead(RWLock *rwl) {
    pthread_mutex_lock(&rwl->mutex);

    rwl->n_readers--;

    if (rwl->n_readers == 0 && !emptyQueue(rwl->waiting_writers)) {
        // El ultimo lector que sale despierta al escritor mas antiguo.
        struct request *wreq = get(rwl->waiting_writers);
        wreq->granted = 1;
        rwl->writer   = 1;
        pthread_cond_signal(&wreq->cond);
    }

    pthread_mutex_unlock(&rwl->mutex);
}

//---------------------------------------------------------------
// Politica de ingreso de un escritor:
//   * Se acepta inmediatamente si no hay lectores ni escritor
//     trabajando.
//   * En caso contrario la solicitud queda pendiente.
//---------------------------------------------------------------
void enterWrite(RWLock *rwl) {
    pthread_mutex_lock(&rwl->mutex);

    if (!rwl->writer && rwl->n_readers == 0) {
        rwl->writer = 1;
        pthread_mutex_unlock(&rwl->mutex);
        return;
    }

    struct request *req = malloc(sizeof(struct request));
    pthread_cond_init(&req->cond, NULL);
    req->granted = 0;
    put(rwl->waiting_writers, req);

    while (!req->granted) {
        pthread_cond_wait(&req->cond, &rwl->mutex);
    }

    pthread_cond_destroy(&req->cond);
    free(req);
    pthread_mutex_unlock(&rwl->mutex);
}

//---------------------------------------------------------------
// Salida de un escritor:
//   * Si hay lectores pendientes, se aceptan todos (uno por uno
//     con cond_signal, nunca con cond_broadcast).
//   * Si no hay lectores pendientes pero si escritores pendientes,
//     se acepta al escritor mas antiguo.
//---------------------------------------------------------------
void exitWrite(RWLock *rwl) {
    pthread_mutex_lock(&rwl->mutex);

    rwl->writer = 0;

    if (!emptyQueue(rwl->waiting_readers)) {
        // Se aceptan todos los lectores pendientes.
        // Se usa pthread_cond_signal uno por uno.
        while (!emptyQueue(rwl->waiting_readers)) {
            struct request *rreq = get(rwl->waiting_readers);
            rreq->granted   = 1;
            rwl->n_readers += 1;
            pthread_cond_signal(&rreq->cond);
        }
    } else if (!emptyQueue(rwl->waiting_writers)) {
        // No hay lectores pendientes: aceptar al escritor mas antiguo.
        struct request *wreq = get(rwl->waiting_writers);
        wreq->granted = 1;
        rwl->writer   = 1;
        pthread_cond_signal(&wreq->cond);
    }

    pthread_mutex_unlock(&rwl->mutex);
}

